import{_ as a,o as i,c as l,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Use the My Alliance Page","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/my-alliance.md","filePath":"how-to/my-alliance.md"}'),t={name:"how-to/my-alliance.md"};function r(n,e,s,c,h,p){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="use-the-my-alliance-page" tabindex="-1">Use the My Alliance Page <a class="header-anchor" href="#use-the-my-alliance-page" aria-label="Permalink to &quot;Use the My Alliance Page&quot;">​</a></h1><p><strong>My Alliance</strong> is the main management page for <code>Alliance Leader</code> and <code>Co-Leader</code> users. It gives you a read-first overview of your alliance, plus the quick actions and offer decisions you are allowed to make.</p><blockquote><p>Screenshot placeholder: my-alliance.png</p></blockquote><h2 id="open-the-page" tabindex="-1">Open the page <a class="header-anchor" href="#open-the-page" aria-label="Permalink to &quot;Open the page&quot;">​</a></h2><p>Select <strong>My Alliance</strong> from the sidebar.</p><p>If you lead more than one alliance, the page shows a selector at the top so you can switch between them.</p><h2 id="what-the-page-is-for" tabindex="-1">What the page is for <a class="header-anchor" href="#what-the-page-is-for" aria-label="Permalink to &quot;What the page is for&quot;">​</a></h2><p>Use <strong>My Alliance</strong> to:</p><ul><li>check alliance totals and recent activity</li><li>open <strong>Alliance analytics</strong></li><li>jump to <strong>Manual input</strong> if your role has it</li><li>review responsible users</li><li>review players</li><li>review recent imports and reports</li><li>review subscription offers for your alliance</li></ul><h2 id="what-you-will-see" tabindex="-1">What you will see <a class="header-anchor" href="#what-you-will-see" aria-label="Permalink to &quot;What you will see&quot;">​</a></h2><p>The page usually includes:</p><ul><li>a top selector when you manage multiple alliances</li><li>a hero area with alliance name, tag, and quick actions</li><li>a subscription offers area</li><li>summary cards</li><li>a usage panel</li><li>responsible users</li><li>players</li><li>recent imports</li><li>recent reports</li></ul><h2 id="subscription-offers-on-this-page" tabindex="-1">Subscription offers on this page <a class="header-anchor" href="#subscription-offers-on-this-page" aria-label="Permalink to &quot;Subscription offers on this page&quot;">​</a></h2><p>If your alliance has a premium offer from its kingdom, this is where you review it.</p><p>Depending on your permissions, you may be able to:</p><ul><li>accept the offer</li><li>reject the offer</li><li>revoke your own accepted access</li></ul><p>Only accepted offers take effect. If there is no offer, the page still shows your current usage and plan situation.</p><h2 id="suspension-warning" tabindex="-1">Suspension warning <a class="header-anchor" href="#suspension-warning" aria-label="Permalink to &quot;Suspension warning&quot;">​</a></h2><p>If the parent kingdom is suspended, this page can show a warning banner. That means alliance actions may be blocked until the kingdom-level problem is resolved.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Use this page as your alliance home base.</li><li>Open player profiles from here when you need deeper player history.</li><li>Review offers carefully before accepting, especially if your alliance already has its own direct subscription.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manage-alliances.html">Create &amp; Manage Alliances</a></li><li><a href="./kick-player.html">Kick a Player from the Alliance</a></li><li><a href="./players-directory.html">Browse &amp; Filter Players</a></li></ul>',23)])])}const f=a(t,[["render",r]]);export{d as __pageData,f as default};
